def binary_search_ascending(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def binary_search_descending(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:  # Azalan dizide, daha küçük elemanlar sağda bulunur
            high = mid - 1
        else:  # Azalan dizide, daha büyük elemanlar solda bulunur
            low = mid + 1
    return -1

def find_peak_index(arr):
    n = len(arr)
    if n == 0:
        return -1
    if n == 1:
        return 0

    low, high = 0, n - 1
    while low <= high:
        mid = low + (high - low) // 2

        # mid elemanının solundaki ve sağındaki elemanlarla karşılaştır
        # Sınır durumlarını (mid=0 veya mid=n-1) dikkate al
        is_greater_than_left = (mid == 0 or arr[mid] > arr[mid - 1])
        is_greater_than_right = (mid == n - 1 or arr[mid] > arr[mid + 1])

        if is_greater_than_left and is_greater_than_right:
            return mid
        elif is_greater_than_left:  # arr[mid] > arr[mid-1] ama arr[mid] < arr[mid+1]
                                  # Zirve sağ tarafta.
            low = mid + 1
        else:  # arr[mid] < arr[mid-1]
               # Zirve sol tarafta.
            high = mid - 1
    return -1 # Geçerli bir bitonik dizi için buraya ulaşılmamalıdır

def search_bitonic_array(arr, target):
    n = len(arr)
    if n == 0:
        return -1
    if n == 1:
        return 0 if arr[0] == target else -1

    peak_index = find_peak_index(arr)

    # Hedef, zirve noktasının kendisi olabilir
    if arr[peak_index] == target:
        return peak_index

    # Artan kısımda (zirvenin solu) arama yap
    result = binary_search_ascending(arr, target, 0, peak_index - 1)
    if result != -1:
        return result

    # Azalan kısımda (zirvenin sağı) arama yap
    result = binary_search_descending(arr, target, peak_index + 1, n - 1)
    return result
